fun main() {
    val fruits = listOf("Apple", "Banana", "Cherry", "Date")

    println("First: ${fruits.first()}")
    println("Last: ${fruits.last()}")
    println("Contains 'Banana': ${fruits.contains("Banana")}")

    // Transform
    val upper = fruits.map { it.uppercase() }
    println("Uppercase: $upper")

    // Filter
    val short = fruits.filter { it.length <= 5 }
    println("Short names: $short")

    // Mutable
    val mutable = mutableListOf("X", "Y")
    mutable.add("Z")
    mutable.remove("X")
    println("Mutable: $mutable")
}
